import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Wallet, ArrowRight, ShoppingBag, CreditCard, 
  LayoutDashboard, Plus, TrendingUp, ChevronRight 
} from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0, totalCartoes: 0 });

  useEffect(() => {
    async function buscarDados() {
      const { data: compras } = await supabase.from('compras').select('valor_total');
      const { data: cartoes } = await supabase.from('cartoes').select('id');

      if (compras) {
        const soma = compras.reduce((acc, item) => acc + parseFloat(item.valor_total), 0);
        setResumo({ 
          total: soma, 
          quantidade: compras.length,
          totalCartoes: cartoes ? cartoes.length : 0
        });
      }
    }
    buscarDados();
  }, []);

  const theme = {
    primary: '#4361ee',
    dark: '#0f172a',
    textMuted: '#64748b',
    gradient1: 'linear-gradient(135deg, #4361ee 0%, #3a0ca3 100%)',
    gradient2: 'linear-gradient(135deg, #7209b7 0%, #f72585 100%)',
    surface: '#ffffff'
  };

  return (
    <div className="fade-in" style={{ padding: '25px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '100px' }}>
      
      {/* HEADER MINIMALISTA */}
      <header style={{ marginBottom: '35px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <span style={{ color: theme.textMuted, fontSize: '0.9rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px' }}>Visão Geral</span>
          <h1 style={{ fontSize: '2rem', margin: '5px 0 0 0', fontWeight: 800, color: theme.dark }}>Olá, Usuário 👋</h1>
        </div>
        <div style={{ background: '#e0e7ff', padding: '10px', borderRadius: '15px' }}>
          <TrendingUp color={theme.primary} size={24} />
        </div>
      </header>

      {/* CARD PRINCIPAL (SALDO/GASTO) */}
      <div style={{ 
        background: theme.dark, 
        borderRadius: '30px', 
        padding: '35px', 
        color: 'white', 
        marginBottom: '35px',
        position: 'relative',
        overflow: 'hidden',
        boxShadow: '0 20px 40px rgba(15, 23, 42, 0.2)'
      }}>
        <div style={{ position: 'relative', zIndex: 2 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: 0.7, marginBottom: '10px' }}>
            <Wallet size={18} />
            <span style={{ fontSize: '0.9rem', fontWeight: 500 }}>Gasto Histórico Total</span>
          </div>
          <h2 style={{ fontSize: '2.8rem', margin: 0, fontWeight: 800, letterSpacing: '-1px' }}>
            R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h2>
          <div style={{ display: 'flex', gap: '20px', marginTop: '25px' }}>
            <div style={{ background: 'rgba(255,255,255,0.1)', padding: '12px 20px', borderRadius: '15px' }}>
              <span style={{ display: 'block', fontSize: '0.75rem', opacity: 0.6 }}>Lançamentos</span>
              <span style={{ fontWeight: 700 }}>{resumo.quantidade} itens</span>
            </div>
            <div style={{ background: 'rgba(255,255,255,0.1)', padding: '12px 20px', borderRadius: '15px' }}>
              <span style={{ display: 'block', fontSize: '0.75rem', opacity: 0.6 }}>Cartões Ativos</span>
              <span style={{ fontWeight: 700 }}>{resumo.totalCartoes} unidades</span>
            </div>
          </div>
        </div>
        {/* Círculos decorativos de fundo */}
        <div style={{ position: 'absolute', top: '-50px', right: '-50px', width: '200px', height: '200px', background: theme.primary, filter: 'blur(80px)', opacity: 0.3 }}></div>
      </div>

      {/* SEÇÃO DE ATALHOS */}
      <h3 style={{ marginBottom: '20px', color: theme.dark, fontWeight: 700, fontSize: '1.2rem' }}>Ações Rápidas</h3>
      
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '15px', marginBottom: '40px' }}>
        
        {/* DASHBOARD */}
        <Link to="/dashboard" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<LayoutDashboard size={26} />} 
            label="Dashboard" 
            sub="Análise"
            bg={theme.surface} 
            color={theme.primary} 
          />
        </Link>

        {/* CARTÕES */}
        <Link to="/cartoes" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<CreditCard size={26} />} 
            label="Cartões" 
            sub="Limites"
            bg={theme.surface} 
            color={theme.secondary} 
          />
        </Link>

        {/* LISTAGEM */}
        <Link to="/listagem" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<ShoppingBag size={26} />} 
            label="Extrato" 
            sub="Histórico"
            bg={theme.surface} 
            color="#00cc66" 
          />
        </Link>

        {/* NOVO */}
        <Link to="/lancamento" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<Plus size={26} />} 
            label="Novo" 
            sub="Lançar"
            bg={theme.primary} 
            color="#fff" 
            isPrimary
          />
        </Link>
      </div>

      {/* FOOTER DO MENU - STATUS RÁPIDO */}
      <div style={{ 
        background: '#f1f5f9', 
        padding: '20px', 
        borderRadius: '20px', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        cursor: 'pointer'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <div style={{ background: 'white', padding: '10px', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}>
             <CreditCard size={20} color={theme.primary} />
          </div>
          <div>
            <span style={{ display: 'block', fontSize: '0.9rem', fontWeight: 700, color: theme.dark }}>Gerenciar Cartões</span>
            <span style={{ fontSize: '0.75rem', color: theme.textMuted }}>{resumo.totalCartoes} métodos de pagamento</span>
          </div>
        </div>
        <ChevronRight size={20} color={theme.textMuted} />
      </div>
    </div>
  );
};

// Sub-componente para os Cards de Ação
const QuickActionCard = ({ icon, label, sub, bg, color, isPrimary }) => (
  <div style={{ 
    background: bg, 
    padding: '20px', 
    borderRadius: '24px', 
    display: 'flex', 
    flexDirection: 'column', 
    gap: '12px',
    boxShadow: isPrimary ? '0 10px 20px rgba(67, 97, 238, 0.3)' : '0 4px 15px rgba(0,0,0,0.05)',
    border: isPrimary ? 'none' : '1px solid #f1f5f9',
    transition: 'transform 0.2s ease',
    height: '100%'
  }}
  onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-5px)'}
  onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
  >
    <div style={{ 
      color: color, 
      background: isPrimary ? 'rgba(255,255,255,0.2)' : `${color}15`, 
      width: '45px', 
      height: '45px', 
      borderRadius: '14px', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center' 
    }}>
      {icon}
    </div>
    <div>
      <span style={{ display: 'block', fontWeight: 800, fontSize: '0.95rem', color: isPrimary ? '#fff' : '#0f172a' }}>{label}</span>
      <span style={{ fontSize: '0.7rem', fontWeight: 600, color: isPrimary ? 'rgba(255,255,255,0.7)' : '#64748b' }}>{sub}</span>
    </div>
  </div>
);

export default Menu;
